```python
const request = require('supertest');
const express = require('express');
const userRoutes = require('./routes/userRoutes');

// Create test app instance
const createTestApp = () => {
  const app = express();
  app.use(express.json());
  app.use('/api/users', userRoutes);

  // Simple error handler for tests
  app.use((err, req, res, next) => {
    res.status(500).json({
      success: false,
      error: err.message
    });
  });

  return app;
};

describe('User API Endpoints', () => {
  let app;

  beforeAll(() => {
    app = createTestApp();
  });

  describe('POST /api/users - Create User', () => {
    it('should create a new user with valid data', async () => {
      const newUser = {
        email: 'test@example.com',
        password: 'securepass123',
        name: 'Test User'
      };

      const response = await request(app)
        .post('/api/users')
        .send(newUser)
        .expect(201);

      expect(response.body.success).toBe(true);
      expect(response.body.data.email).toBe('test@example.com');
      expect(response.body.data.name).toBe('Test User');
      expect(response.body.data.password).toBeUndefined(); // Password should not be returned
      expect(response.body.data.id).toBeDefined();
    });

    it('should reject user creation with missing email', async () => {
      const invalidUser = {
        password: 'securepass123',
        name: 'Test User'
      };

      const response = await request(app)
        .post('/api/users')
        .send(invalidUser)
        .expect(400);

      expect(response.body.success).toBe(false);
      expect(response.body.details).toContain('Email is required');
    });

    it('should reject user creation with invalid email format', async () => {
      const invalidUser = {
        email: 'not-an-email',
        password: 'securepass123',
        name: 'Test User'
      };

      const response = await request(app)
        .post('/api/users')
        .send(invalidUser)
        .expect(400);

      expect(response.body.success).toBe(false);
      expect(response.body.details).toContain('Invalid email format');
    });

    it('should reject user creation with short password', async () => {
      const invalidUser = {
        email: 'test@example.com',
        password: 'short',
        name: 'Test User'
      };

      const response = await request(app)
        .post('/api/users')
        .send(invalidUser)
        .expect(400);

      expect(response.body.success).toBe(false);
      expect(response.body.details).toContain('Password must be at least 8 characters long');
    });

    it('should reject duplicate email registration', async () => {
      const user = {
        email: 'duplicate@example.com',
        password: 'securepass123',
        name: 'First User'
      };

      // Create first user
      await request(app)
        .post('/api/users')
        .send(user)
        .expect(201);

      // Try to create second user with same email
      const response = await request(app)
        .post('/api/users')
        .send(user)
        .expect(409);

      expect(response.body.success).toBe(false);
      expect(response.body.error).toContain('already exists');
    });
  });

  describe('GET /api/users - List Users', () => {
    it('should return all users', async () => {
      const response = await request(app)
        .get('/api/users')
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(Array.isArray(response.body.data)).toBe(true);
      expect(response.body.count).toBeDefined();
    });

    it('should filter users by name', async () => {
      const response = await request(app)
        .get('/api/users?name=Test')
        .expect(200);

      expect(response.body.success).toBe(true);
      // Verify all returned users match the filter
      response.body.data.forEach(user => {
        expect(user.name.toLowerCase()).toContain('test');
      });
    });
  });

  describe('GET /api/users/:id - Get Single User', () => {
    it('should return a user by valid ID', async () => {
      const response = await request(app)
        .get('/api/users/1')
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.id).toBe(1);
    });

    it('should return 404 for non-existent user', async () => {
      const response = await request(app)
        .get('/api/users/99999')
        .expect(404);

      expect(response.body.success).toBe(false);
      expect(response.body.error).toContain('not found');
    });

    it('should return 400 for invalid ID format', async () => {
      const response = await request(app)
        .get('/api/users/invalid')
        .expect(400);

      expect(response.body.success).toBe(false);
      expect(response.body.error).toContain('Invalid user ID');
    });
  });

  describe('PUT /api/users/:id - Update User', () => {
    it('should update user with valid data', async () => {
      const updateData = {
        name: 'Updated Name'
      };

      const response = await request(app)
        .put('/api/users/1')
        .send(updateData)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.name).toBe('Updated Name');
    });

    it('should reject partial update with invalid email', async () => {
      const updateData = {
        email: 'invalid-email'
      };

      const response = await request(app)
        .put('/api/users/1')
        .send(updateData)
        .expect(400);

      expect(response.body.success).toBe(false);
    });
  });

  describe('DELETE /api/users/:id - Delete User', () => {
    it('should delete existing user', async () => {
      const response = await request(app)
        .delete('/api/users/1')
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.message).toContain('deleted');
    });

    it('should return 404 when deleting non-existent user', async () => {
      const response = await request(app)
        .delete('/api/users/99999')
        .expect(404);

      expect(response.body.success).toBe(false);
    });
  });
});
```



## Common Mistakes

- Accepting AI-generated code without reviewing it for security vulnerabilities or logic errors
- Not providing enough context in prompts, leading to generic or mismatched code patterns
- Skipping input validation, especially for edge cases like empty strings, special characters, or boundary values
- Forgetting to handle async errors properly, leading to unhandled promise rejections
- Not sanitizing response data, accidentally exposing sensitive fields like passwords or tokens
- Missing proper HTTP status codes for different error scenarios (400 for validation, 401 for auth, 404 for not found, 500 for server errors)
- Over-relying on AI without understanding the generated code, making debugging difficult later
- Not integrating AI-generated endpoints with existing middleware or error handling patterns


## Best Practices

- Start prompts with context about your existing codebase structure, naming conventions, and patterns
- Always review AI-generated code before integration, checking for security, performance, and consistency
- Add comprehensive input validation that handles both format checking and business rules
- Implement consistent error handling with proper HTTP status codes and meaningful error messages
- Sanitize all responses to exclude sensitive data before sending to clients
- Write tests for AI-generated endpoints to verify functionality and catch regressions
- Iterate on AI suggestions using follow-up prompts to refine specific aspects like error messages or validation rules
- Document any custom business logic or requirements that the AI should know about for future suggestions
- Use middleware for cross-cutting concerns rather than duplicating logic in each route handler
- Keep AI-generated code aligned with your project's coding standards through explicit guidance in prompts

