    'src/features',
    'src/components',
    'src/utils',
    'src/types',
    'src/api',
    'src/hooks',
    'src/store',
    'tests',
    'package.json',
    'tsconfig.json',
    '.env.example',
    'vite.config.ts'
  ];

  const missingPaths = [];

  for (const p of requiredPaths) {
