{
  "spec_version": "1.0",
  "app_name": "Smart Todo App",
  "description": "A minimalist task management application with filtering and persistence capabilities",
  "data_models": {
    "Task": {
      "id": {"type": "integer", "auto_increment": true, "primary_key": true},
      "title": {"type": "text", "required": true, "max_length": 200},
      "description": {"type": "text", "required": false},
      "status": {"type": "text", "default": "active", "enum": ["active", "completed"]},
      "priority": {"type": "text", "default": "medium", "enum": ["low", "medium", "high"]},
      "created_at": {"type": "timestamp", "default": "CURRENT_TIMESTAMP"},
      "updated_at": {"type": "timestamp", "default": "CURRENT_TIMESTAMP", "auto_update": true}
    }
  },
  "api_endpoints": {
    "GET /tasks": {"description": "Retrieve all tasks with optional filtering", "params": ["status", "priority"]},
    "GET /tasks/:id": {"description": "Retrieve a single task by ID"},
    "POST /tasks": {"description": "Create a new task", "body": ["title", "description", "priority"]},
    "PUT /tasks/:id": {"description": "Update an existing task", "body": ["title", "description", "status", "priority"]},
    "DELETE /tasks/:id": {"description": "Delete a task by ID"}
  },
  "acceptance_criteria": {
    "add_task": "User can create a task with title; task appears in list immediately after creation",
    "list_tasks": "All tasks display in chronological order (newest first) with title, status indicator, and priority badge",
    "filter_tasks": "Clicking 'All/Active/Completed' buttons shows only matching tasks; filter state persists during session",
    "toggle_status": "Clicking checkbox toggles task status; completed tasks show strikethrough styling",
    "data_persistence": "Created tasks survive server restart; database file persists in ./data directory"
  }
}
