    "GET /tasks": {"description": "Retrieve all tasks with optional filtering", "params": ["status", "priority"]},
    "GET /tasks/:id": {"description": "Retrieve a single task by ID"},
    "POST /tasks": {"description": "Create a new task", "body": ["title", "description", "priority"]},
    "PUT /tasks/:id": {"description": "Update an existing task", "body": ["title", "description", "status", "priority"]},
    "DELETE /tasks/:id": {"description": "Delete a task by ID"}
