import sqlite3
from flask import Flask, request, jsonify, g
from pathlib import Path
from datetime import datetime

app = Flask(__name__)
DATABASE = Path(__file__).parent / 'data' / 'todos.db'

# Ensure data directory exists before creating database
DATABASE.parent.mkdir(exist_ok=True)

def get_db():
    """Get database connection for current request context"""
    if 'db' not in g:
        # Enable Row factory for dict-like row access
        g.db = sqlite3.connect(DATABASE)
        g.db.row_factory = sqlite3.Row
    return g.db

@app.teardown_appcontext
def close_db(error):
    """Automatically close database connection at request end"""
    db = g.pop('db', None)
    if db is not None:
        db.close()

def init_db():
    """Initialize database schema - creates tasks table if not exists"""
    db = get_db()
    db.executescript('''
        CREATE TABLE IF NOT EXISTS tasks (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            title TEXT NOT NULL,
            description TEXT,
            status TEXT DEFAULT 'active' CHECK(status IN ('active', 'completed')),
            priority TEXT DEFAULT 'medium' CHECK(priority IN ('low', 'medium', 'high')),
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        );
        -- Ensure updated_at auto-updates on row changes
        CREATE TRIGGER IF NOT EXISTS update_timestamp UPDATE ON tasks BEGIN
            UPDATE tasks SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;
        END;
    ''')
    db.commit()
    print("[INFO] Database initialized successfully")


@app.route('/tasks', methods=['GET'])
def get_tasks():
    """GET /tasks - Retrieve all tasks with optional status/priority filtering"""
    db = get_db()
    query = 'SELECT * FROM tasks'
    conditions = []
    params = []

    # Apply filters if provided as query parameters
    if request.args.get('status'):
        conditions.append('status = ?')
        params.append(request.args.get('status'))
    if request.args.get('priority'):
        conditions.append('priority = ?')
        params.append(request.args.get('priority'))

    # Build final query with WHERE clause if filters exist
    if conditions:
        query += ' WHERE ' + ' AND '.join(conditions)

    # Always order by created_at descending (newest first)
    query += ' ORDER BY created_at DESC'

    cursor = db.execute(query, params)
    tasks = [dict(row) for row in cursor.fetchall()]
    return jsonify({"tasks": tasks, "count": len(tasks)})

@app.route('/tasks', methods=['POST'])
def create_task():
    """POST /tasks - Create a new task with title (required) and optional fields"""
    data = request.get_json()

    # Validate required fields
    if not data or 'title' not in data:
        return jsonify({"error": "Title is required"}), 400

    # Sanitize and validate title length
    title = data['title'].strip()
    if len(title) > 200:
        return jsonify({"error": "Title must be 200 characters or less"}), 400
    if len(title) < 1:
        return jsonify({"error": "Title cannot be empty"}), 400

    db = get_db()
    cursor = db.execute(
        '''INSERT INTO tasks (title, description, priority) VALUES (?, ?, ?)',
        (title, data.get('description', ''), data.get('priority', 'medium'))
    )
    db.commit()

    # Return created task with generated ID
    return jsonify({
        "message": "Task created successfully",
        "task": {"id": cursor.lastrowid, "title": title}
    }), 201

@app.route('/tasks/<int:task_id>', methods=['PUT'])
def update_task(task_id):
    """PUT /tasks/:id - Update task fields (title, description, status, priority)"""
    data = request.get_json()
    if not data:
        return jsonify({"error": "Request body required"}), 400

    db = get_db()

    # Build dynamic UPDATE query based on provided fields
    fields = []
    values = []
    allowed_fields = ['title', 'description', 'status', 'priority']

    for field in allowed_fields:
        if field in data:
            fields.append(f'{field} = ?')
            values.append(data[field])

    if not fields:
        return jsonify({"error": "No valid fields to update"}), 400

    values.append(task_id)
    query = f'UPDATE tasks SET {', '.join(fields)} WHERE id = ?'

    cursor = db.execute(query, values)
    db.commit()

    if cursor.rowcount == 0:
        return jsonify({"error": "Task not found"}), 404

    return jsonify({"message": "Task updated successfully"})

@app.route('/tasks/<int:task_id>', methods=['DELETE'])
def delete_task(task_id):
    """DELETE /tasks/:id - Remove a task by ID"""
    db = get_db()
    cursor = db.execute('DELETE FROM tasks WHERE id = ?', (task_id,))
    db.commit()

    if cursor.rowcount == 0:
        return jsonify({"error": "Task not found"}), 404

    return jsonify({"message": "Task deleted successfully"})

# Initialize database on startup
with app.app_context():
    init_db()

if __name__ == '__main__':
    # Enable debug mode for development (auto-reload, better error messages)
    app.run(debug=True, host='0.0.0.0', port=5000)

// Example 3: Simple React Frontend (App.jsx)
import React, { useState, useEffect } from 'react';

const API_BASE = 'http://localhost:5000';

function App() {
  const [tasks, setTasks] = useState([]);
  const [filter, setFilter] = useState('all'); // 'all', 'active', 'completed'
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);

  // Fetch tasks whenever filter changes
  useEffect(() => {
    fetchTasks();
  }, [filter]);

  const fetchTasks = async () => {
    setIsLoading(true);
    setError(null);
    try {
      // Build URL with filter parameter (omit for 'all' to get unfiltered results)
      const url = filter === 'all' 
        ? `${API_BASE}/tasks` 
        : `${API_BASE}/tasks?status=${filter}`;

      const response = await fetch(url);
      if (!response.ok) throw new Error('Failed to fetch tasks');

      const data = await response.json();
      setTasks(data.tasks);
    } catch (err) {
      setError(err.message);
      console.error('Fetch error:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const createTask = async (e) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;

    try {
      const response = await fetch(`${API_BASE}/tasks`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title: newTaskTitle.trim() }),
      });

      if (!response.ok) throw new Error('Failed to create task');

      setNewTaskTitle(''); // Clear input on success
      fetchTasks(); // Refresh task list
    } catch (err) {
      setError(err.message);
    }
  };

  const toggleTaskStatus = async (task) => {
    // Determine new status (toggle between 'active' and 'completed')
    const newStatus = task.status === 'active' ? 'completed' : 'active';

    try {
      const response = await fetch(`${API_BASE}/tasks/${task.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: newStatus }),
      });

      if (!response.ok) throw new Error('Failed to update task');

      // Update local state without re-fetching (optimistic update)
      setTasks(tasks.map(t => 
        t.id === task.id ? { ...t, status: newStatus } : t
      ));
    } catch (err) {
      setError(err.message);
    }
  };

  const deleteTask = async (taskId) => {
    if (!window.confirm('Delete this task?')) return;

    try {
      const response = await fetch(`${API_BASE}/tasks/${taskId}`, {
        method: 'DELETE',
      });

      if (!response.ok) throw new Error('Failed to delete task');

      // Remove from local state
      setTasks(tasks.filter(t => t.id !== taskId));
    } catch (err) {
      setError(err.message);
    }
  };

  // Calculate task counts for filter buttons
  const taskCounts = tasks.reduce((acc, task) => {
    acc[task.status] = (acc[task.status] || 0) + 1;
    return acc;
  }, { active: 0, completed: 0 });

  return (
    <div className="app-container">
      <h1>Smart Todo App</h1>

      {/* Error display */}
      {error && <div className="error-banner">{error}</div>}

      {/* Add task form */}
      <form onSubmit={createTask} className="add-task-form">
        <input
          type="text"
          value={newTaskTitle}
          onChange={(e) => setNewTaskTitle(e.target.value)}
          placeholder="Enter task title..."
          maxLength={200}
        />
        <button type="submit" disabled={!newTaskTitle.trim()}>
          Add Task
        </button>
      </form>

      {/* Filter controls */}
      <div className="filter-controls">
        {['all', 'active', 'completed'].map(filterOption => (
          <button
            key={filterOption}
            onClick={() => setFilter(filterOption)}
            className={filter === filterOption ? 'active' : ''}
          >
            {filterOption.charAt(0).toUpperCase() + filterOption.slice(1)}
          </button>
        ))}
      </div>

      {/* Task list */}
      <ul className="task-list">
        {isLoading ? (
          <li className="loading">Loading tasks...</li>
        ) : tasks.length === 0 ? (
          <li className="empty-state">No tasks found</li>
        ) : (
          tasks.map(task => (
            <li key={task.id} className={`task-item ${task.status}`}>
              <label>
                <input
                  type="checkbox"
                  checked={task.status === 'completed'}
                  onChange={() => toggleTaskStatus(task)}
                />
                <span className={task.status === 'completed' ? 'completed' : ''}>
                  {task.title}
                </span>
              </label>
              <span className={`priority-badge ${task.priority}`}>
                {task.priority}
              </span>
              <button 
                onClick={() => deleteTask(task.id)}
                className="delete-btn"
                aria-label="Delete task"
              >
                ×
              </button>
            </li>
          ))
        )}
      </ul>
    </div>
  );
}

export default App;

