        return {
            'name': 'REST API Template',
            'description': 'Production-ready REST API with authentication and database',
            'prompt_template': '''
Create a REST API project with:
- Framework: {framework}
- Database: {database}
- Auth: {auth_method}

Directory structure:
- /src/api (routes, controllers)
- /src/models (database models)
- /src/services (business logic)
- /src/middleware (auth, validation, error handling)
- /src/utils (helpers, validators)
- /tests (unit and integration)
- /docs (API documentation)

Include:
- Config management with environment variables
- Database migrations setup
- JWT authentication middleware
- Rate limiting configuration
- API versioning structure
- Swagger/OpenAPI documentation
- Health check endpoint
- Structured logging

{additional_requirements}
''',
            'required_files': [
                'package.json', 'tsconfig.json', '.env.example',
                'src/index.ts', 'src/api/routes/index.ts'
            ],
            'validation_rules': [
                'check_package_json_dependencies',
                'verify_typescript_config',
                'validate_env_template_completeness'
            ]
        }

    def generate_prompt(self, template_name, context):
        """Generate a scaffolding prompt from a template and context."""
        template = self.templates.get(template_name)
        if not template:
            raise ValueError(f'Template "{template_name}" not found')

        return template['prompt_template'].format(**context)

    def validate_output(self, template_name, generated_structure):
        """Validate that generated structure matches template requirements."""
        template = self.templates.get(template_name)
        if not template:
            return False

        missing_files = []
        for required_file in template['required_files']:
            if required_file not in generated_structure:
                missing_files.append(required_file)

        if missing_files:
            print(f'Missing required files: {missing_files}')
            return False

        return True

    def add_template(self, name, template_def):
        """Add a custom template to the registry."""
        self.templates[name] = template_def

    def list_templates(self):
        """List all available templates."""
        return {name: info['description'] for name, info in self.templates.items()}


